// Instead of a blocking loop:
// for(let i=0; i<1e9; i++) { count++; }

// We split the work into multiple Macrotasks:
let count = 0;
function countToBillion() {
  let end = count + 1_000_000;
  while(count < end) { count++; }

  if (count < 1_000_000_000) {
    // Schedule the next chunk as a new Macrotask.
    // This allows the Event Loop to render the UI in between chunks!
    setTimeout(countToBillion, 0); 
  } else {
    console.log('Done!');
  }
}
countToBillion();

